#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y, Z; // use long long to avoid overflow
        scanf("%lld %lld %lld", &X, &Y, &Z);
        if (X + 2 * Z >= Y) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

